export type ClefType = 'treble' | 'bass';
export type GameMode = 'single' | 'chords' | 'beams';

export interface Note {
  midi: number;
  name: string; // e.g., "C"
  octave: number; // e.g., 4
  accidental?: '#' | 'b' | null;
  duration?: 'w' | 'h' | 'q' | '8' | '16';
}

export interface Chord {
  notes: Note[];
  duration?: string;
}

export interface ExerciseItem {
  id: string;
  notes: Note[]; // Array of notes. If length > 1 and mode is chord, it's a chord.
  status: 'pending' | 'correct' | 'incorrect';
  userInput?: number[]; // MIDI numbers inputs
  isBeamGroup?: boolean; // For visual grouping
}

export interface GameSettings {
  clef: ClefType;
  useAccidentals: boolean;
  mode: GameMode;
}

export interface KeyConfig {
  midi: number;
  type: 'white' | 'black';
  label: string;
  leftOffset?: number; // For CSS positioning of black keys
}

import { KeyConfig } from './types';

// Middle C is MIDI 60 (C4)
export const MIDDLE_C = 60;

// To achieve 35 white keys with 19th position as Middle C:
// 18 white keys below C4.
// White keys in an octave: 7.
// 18 / 7 = 2 octaves + 4 keys.
// C4 -> C3 -> C2.
// Below C2: B1, A1, G1, F1.
// So start at F1 (MIDI 29).
// Let's verify:
// F1, G1, A1, B1 (4)
// C2-B2 (7)
// C3-B3 (7)
// C4 (19th key!)
export const START_MIDI = 29; // F1
export const TOTAL_WHITE_KEYS = 35;

// Generate Keyboard Map
export const generateKeyboardMap = (): KeyConfig[] => {
  const keys: KeyConfig[] = [];
  let currentMidi = START_MIDI;
  let whiteKeyCount = 0;

  // We need to generate enough notes to cover 35 white keys.
  // A safe upper bound loop, we break when whiteKeyCount hits target
  while (whiteKeyCount < TOTAL_WHITE_KEYS) {
    const octave = Math.floor(currentMidi / 12) - 1;
    const noteInOctave = currentMidi % 12;

    // MIDI 0 is C-1. 
    // 0:C, 1:C#, 2:D, 3:D#, 4:E, 5:F, 6:F#, 7:G, 8:G#, 9:A, 10:A#, 11:B

    const isBlack = [1, 3, 6, 8, 10].includes(noteInOctave);
    let name = '';

    switch(noteInOctave) {
      case 0: name = 'C'; break;
      case 1: name = 'C#'; break;
      case 2: name = 'D'; break;
      case 3: name = 'D#'; break;
      case 4: name = 'E'; break;
      case 5: name = 'F'; break;
      case 6: name = 'F#'; break;
      case 7: name = 'G'; break;
      case 8: name = 'G#'; break;
      case 9: name = 'A'; break;
      case 10: name = 'A#'; break;
      case 11: name = 'B'; break;
    }

    if (!isBlack) {
      whiteKeyCount++;
    }

    keys.push({
      midi: currentMidi,
      type: isBlack ? 'black' : 'white',
      label: `${name}${octave}`
    });

    currentMidi++;
  }
  return keys;
};

export const KEYBOARD_MAP = generateKeyboardMap();

import * as Tone from 'tone';

class AudioService {
  private synth: Tone.PolySynth | null = null;
  private initialized = false;

  async init() {
    if (this.initialized) return;

    await Tone.start();

    this.synth = new Tone.PolySynth(Tone.Synth, {
      oscillator: {
        type: "triangle"
      },
      envelope: {
        attack: 0.02,
        decay: 0.1,
        sustain: 0.3,
        release: 1
      }
    }).toDestination();

    // Lower volume a bit
    this.synth.volume.value = -8;

    this.initialized = true;
  }

  playNote(midi: number, duration: string = '8n') {
    if (!this.synth) return;
    const freq = Tone.Frequency(midi, "midi").toNote();
    this.synth.triggerAttackRelease(freq, duration);
  }

  playChord(midis: number[], duration: string = '8n') {
    if (!this.synth) return;
    const freqs = midis.map(m => Tone.Frequency(m, "midi").toNote());
    this.synth.triggerAttackRelease(freqs, duration);
  }

  startNote(midi: number) {
     if (!this.synth) return;
     const freq = Tone.Frequency(midi, "midi").toNote();
     this.synth.triggerAttack(freq);
  }

  stopNote(midi: number) {
    if (!this.synth) return;
    const freq = Tone.Frequency(midi, "midi").toNote();
    this.synth.triggerRelease(freq);
  }
}

export const audioService = new AudioService();

import { Note, ExerciseItem, GameSettings, GameMode } from '../types';
import { v4 as uuidv4 } from 'uuid';

// Ranges for generation
const TREBLE_MIN = 60; // C4
const TREBLE_MAX = 84; // C6
const BASS_MIN = 36;   // C2
const BASS_MAX = 60;   // C4

const getRandomInt = (min: number, max: number) => {
  return Math.floor(Math.random() * (max - min + 1)) + min;
};

const midiToNote = (midi: number, useAccidentals: boolean): Note => {
  const noteNames = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];
  const octave = Math.floor(midi / 12) - 1;
  const index = midi % 12;

  let name = noteNames[index];
  let accidental: '#' | 'b' | null = null;

  if (name.includes('#')) {
    accidental = '#';
    name = name[0]; // Strip #
  }

  // Naive accidental handling (prefer sharps for now for simplicity in generation logic)
  // In a real theory app, we'd check key signatures. 

  return {
    midi,
    name,
    octave,
    accidental
  };
};

export const generateExercise = (settings: GameSettings): ExerciseItem[] => {
  const items: ExerciseItem[] = [];
  const min = settings.clef === 'treble' ? TREBLE_MIN : BASS_MIN;
  const max = settings.clef === 'treble' ? TREBLE_MAX : BASS_MAX;

  // Limit max items per turn to 6 as requested
  const itemCount = getRandomInt(3, 6);

  if (settings.mode === 'single') {
    for (let i = 0; i < itemCount; i++) {
      let midi = getRandomInt(min, max);

      if (!settings.useAccidentals) {
        // Force to white key
        const noteInOctave = midi % 12;
        if ([1, 3, 6, 8, 10].includes(noteInOctave)) {
          midi -= 1; // Shift down to white key
        }
      }

      items.push({
        id: uuidv4(),
        notes: [midiToNote(midi, settings.useAccidentals)],
        status: 'pending'
      });
    }
  } 
  else if (settings.mode === 'chords') {
    for (let i = 0; i < itemCount; i++) {
      const root = getRandomInt(min, max - 7); // Ensure room for chord

      if (!settings.useAccidentals) {
         const noteInOctave = root % 12;
         if ([1, 3, 6, 8, 10].includes(noteInOctave)) {
           // Skip accidental roots if disabled, though chords might naturally have them? 
           // Prompt says "select if they want to use accidentals". 
           // If false, strictly C Major chords logic? Or just roots are natural?
           // Let's assume C Major scale chords only if accidentals off.
         }
      }

      // Generate Triad (Root, +4/+3, +7) or Seventh
      const isSeventh = Math.random() > 0.7;
      const chordMidis = [root];

      // Simple major/minor construction
      const third = Math.random() > 0.5 ? 4 : 3; // Major vs Minor
      const fifth = 7;

      chordMidis.push(root + third);
      chordMidis.push(root + fifth);

      if (isSeventh) {
        chordMidis.push(root + 10 + (Math.random() > 0.5 ? 1 : 0));
      }

      // Filter accidentals if strictly forbidden
      const finalNotes = chordMidis.map(m => midiToNote(m, true)); // Allow internal accidentals for correct chord structure representation

      // Check if we need to filter out chords with black keys if accidentals are disabled globally
      if (!settings.useAccidentals) {
         const hasBlack = chordMidis.some(m => [1,3,6,8,10].includes(m % 12));
         if (hasBlack) {
            i--; // Retry
            continue;
         }
      }

      items.push({
        id: uuidv4(),
        notes: finalNotes,
        status: 'pending'
      });
    }
  }
  else if (settings.mode === 'beams') {
    // Generate sequence of 8ths or 16ths
    for (let i = 0; i < itemCount; i++) {
      let midi = getRandomInt(min, max);
       if (!settings.useAccidentals) {
        const noteInOctave = midi % 12;
        if ([1, 3, 6, 8, 10].includes(noteInOctave)) midi -= 1;
      }

      const duration = Math.random() > 0.5 ? '8' : '16';

      const note = midiToNote(midi, settings.useAccidentals);
      note.duration = duration;

      items.push({
        id: uuidv4(),
        notes: [note],
        status: 'pending',
        isBeamGroup: true
      });
    }
  }

  return items;
};

import React, { useEffect, useState } from 'react';
import { KEYBOARD_MAP, MIDDLE_C } from '../constants';
import { audioService } from '../services/audioService';
import { KeyConfig } from '../types';

interface PianoProps {
  onNotePlay: (midi: number) => void;
  onNoteStop?: (midi: number) => void;
  activeNotes: number[]; // Notes generated by system (for playback visualization if needed, or correctness)
  selectedNotes: number[]; // Notes currently held by user
  showLabels?: boolean;
}

const Piano: React.FC<PianoProps> = ({ onNotePlay, onNoteStop, selectedNotes, showLabels }) => {
  const [pressedKeys, setPressedKeys] = useState<Set<number>>(new Set());

  const handleMouseDown = (midi: number) => {
    if (!pressedKeys.has(midi)) {
      audioService.startNote(midi);
      onNotePlay(midi);
      setPressedKeys(prev => new Set(prev).add(midi));
    }
  };

  const handleMouseUp = (midi: number) => {
    if (pressedKeys.has(midi)) {
      audioService.stopNote(midi);
      if (onNoteStop) onNoteStop(midi);
      setPressedKeys(prev => {
        const next = new Set(prev);
        next.delete(midi);
        return next;
      });
    }
  };

  // Allow global mouse up to stop stuck notes
  useEffect(() => {
    const handleGlobalUp = () => {
      pressedKeys.forEach(midi => {
        audioService.stopNote(midi);
        if (onNoteStop) onNoteStop(midi);
      });
      setPressedKeys(new Set());
    };
    window.addEventListener('mouseup', handleGlobalUp);
    return () => window.removeEventListener('mouseup', handleGlobalUp);
  }, [pressedKeys, onNoteStop]);

  // Render Logic
  // White keys are laid out in flex. Black keys are absolute positioned relative to container.

  const whiteKeys = KEYBOARD_MAP.filter(k => k.type === 'white');
  const blackKeys = KEYBOARD_MAP.filter(k => k.type === 'black');

  // Calculate left positions for black keys
  // A standard octave has 7 white keys.
  // C# is between C and D (approx 14.3% + adjustment)
  // We can treat white keys as having fixed width units.

  // Width percentage for one white key
  const wkWidth = 100 / whiteKeys.length;

  return (
    <div className="relative w-full h-48 md:h-64 bg-slate-800 rounded-lg overflow-hidden select-none shadow-2xl border-t-8 border-slate-900">

      {/* White Keys Container */}
      <div className="flex w-full h-full">
        {whiteKeys.map((key) => {
            const isSelected = selectedNotes.includes(key.midi);
            const isPressed = pressedKeys.has(key.midi);

            return (
              <div
                key={key.midi}
                onMouseDown={() => handleMouseDown(key.midi)}
                onMouseEnter={(e) => { if(e.buttons === 1) handleMouseDown(key.midi) }}
                onMouseLeave={() => handleMouseUp(key.midi)}
                className={`
                  relative h-full border-r border-slate-300 last:border-r-0 z-10 cursor-pointer
                  transition-colors duration-75
                  ${isSelected ? 'bg-blue-300' : isPressed ? 'bg-gray-200' : 'bg-white'}
                  active:bg-gray-300
                  rounded-b-md
                `}
                style={{ width: `${wkWidth}%` }}
              >
                {key.midi === MIDDLE_C && (
                  <div className="absolute bottom-2 left-1/2 -translate-x-1/2 text-xs text-slate-400 font-bold">C4</div>
                )}
              </div>
            );
        })}
      </div>

      {/* Black Keys Container (Overlay) */}
      <div className="absolute top-0 left-0 w-full h-2/3 pointer-events-none">
         {blackKeys.map((key) => {
            // Find index of the white key just BEFORE this black key in the sorted map
            // The map contains all keys.
            // Logic: Calculate distance from start in terms of white keys.
            // C# is after C. 
            // MIDI order: ... F1(29) ...
            // We need to map MIDI to a "White Key Index".

            // let's calculate exact offset based on white key array index
            const previousWhiteIndex = whiteKeys.findIndex(wk => wk.midi === key.midi - 1);

            // Adjustments for specific positions (C#, D# vs F#, G#, A# spacing)
            // Standard piano spacing is nuanced, but roughly:
            // C# center is on the line between C and D.

            if (previousWhiteIndex === -1) return null; // Should not happen

            // Left position: (index + 1) * unitWidth - (blackWidth / 2)
            // Black key width is usually ~60% of white key
            const leftPercent = (previousWhiteIndex + 1) * wkWidth - (wkWidth * 0.3); // roughly centered on border

            const isSelected = selectedNotes.includes(key.midi);
            const isPressed = pressedKeys.has(key.midi);

            return (
              <div
                key={key.midi}
                className="absolute h-full pointer-events-auto z-20"
                style={{ 
                  left: `${leftPercent}%`, 
                  width: `${wkWidth * 0.6}%` 
                }}
              >
                <div 
                  onMouseDown={() => handleMouseDown(key.midi)}
                  onMouseEnter={(e) => { if(e.buttons === 1) handleMouseDown(key.midi) }}
                  onMouseLeave={() => handleMouseUp(key.midi)}
                  className={`
                    w-full h-full rounded-b-md cursor-pointer border-x border-b border-black shadow-md
                    transition-colors duration-75
                    ${isSelected ? 'bg-blue-600' : isPressed ? 'bg-slate-700' : 'bg-piano-black'}
                  `}
                />
              </div>
            );
         })}
      </div>
    </div>
  );
};

export default Piano;

import React, { useEffect, useRef } from 'react';
import Vex from 'vexflow';
import { ExerciseItem, ClefType } from '../types';

interface SheetMusicProps {
  items: ExerciseItem[];
  clef: ClefType;
  activeIndex: number;
}

const SheetMusic: React.FC<SheetMusicProps> = ({ items, clef, activeIndex }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current || items.length === 0) return;

    // Clear previous render
    containerRef.current.innerHTML = '';

    const { Factory } = Vex.Flow;
    // Viewport width management
    const width = containerRef.current.clientWidth;
    const height = 200;

    const vf = new Factory({
      renderer: { elementId: containerRef.current, width, height }
    });

    const score = vf.EasyScore();
    const system = vf.System();

    // Convert Exercise Items to VexFlow Notes
    const staveNotes = items.map((item, index) => {
      // Logic for note keys: e.g. "c/4"
      const keys = item.notes.map(n => `${n.name}/${n.octave}`);

      const accids = item.notes.map(n => n.accidental || '');

      // Determine duration. Default to quarter 'q'. If beam mode, uses item.notes[0].duration
      const duration = item.notes[0].duration || 'q';
      const type = item.notes[0].duration || 'q';

      const isActive = index === activeIndex;
      const color = item.status === 'correct' ? '#22c55e' : 
                    item.status === 'incorrect' ? '#ef4444' : 
                    isActive ? '#3b82f6' : 'black';

      // Create Note
      const note = score.notes(`${keys.join(', ')}`, { stem: 'up', clef });

      // Apply accidentals
      item.notes.forEach((n, idx) => {
         if (n.accidental) {
           note.addModifier(new Vex.Flow.Accidental(n.accidental), idx);
         }
      });

      note.setDuration(duration);

      // Style
      note.setStyle({ fillStyle: color, strokeStyle: color });

      return note;
    });

    // Handle Beams (if Mode 3)
    // We need to pass the notes to system.addStave, but beams are separate objects in EasyScore usually handled by .beam()
    // but here we are constructing manually.

    // Group notes into a voice
    const voice = score.voice(staveNotes);

    // Auto Beaming logic if needed, or specific beams based on our data
    // VexFlow Factory 'Beam' can connect notes.
    const beams = Vex.Flow.Beam.generateBeams(staveNotes, {
        groups: [new Vex.Flow.Fraction(4, 8)] // Group 8ths by 4
    });

    // Add stave to system
    const stave = system.addStave({
      voices: [voice]
    });

    stave.addClef(clef);
    stave.addTimeSignature(items[0]?.isBeamGroup ? '4/4' : `${items.length}/4`); // Visual time sig

    vf.draw();

    // Draw beams manually if Factory didn't auto-handle inside draw() via context
    beams.forEach(b => b.setContext(vf.getContext()).draw());

  }, [items, clef, activeIndex]);

  return (
    <div className="w-full flex justify-center bg-white rounded-xl shadow-inner p-4 overflow-hidden mb-6">
       <div ref={containerRef} className="w-full max-w-3xl" />
    </div>
  );
};

export default SheetMusic;

import React, { useState, useEffect, useCallback } from 'react';
import { Music, Settings as SettingsIcon, Volume2, RotateCcw, Check, Play } from 'lucide-react';
import Piano from './components/Piano';
import SheetMusic from './components/SheetMusic';
import { GameSettings, ExerciseItem } from './types';
import { generateExercise } from './services/logic';
import { audioService } from './services/audioService';

const App: React.FC = () => {
  // --- State ---
  const [isPlaying, setIsPlaying] = useState(false);
  const [settings, setSettings] = useState<GameSettings>({
    clef: 'treble',
    useAccidentals: false,
    mode: 'single'
  });

  const [exerciseItems, setExerciseItems] = useState<ExerciseItem[]>([]);
  const [cursorIndex, setCursorIndex] = useState(0);
  const [selectedChordNotes, setSelectedChordNotes] = useState<number[]>([]);
  const [feedbackMessage, setFeedbackMessage] = useState<string | null>(null);

  // --- Actions ---

  const startGame = async () => {
    await audioService.init();
    const newItems = generateExercise(settings);
    setExerciseItems(newItems);
    setCursorIndex(0);
    setSelectedChordNotes([]);
    setFeedbackMessage(null);
    setIsPlaying(true);
  };

  const nextTurn = () => {
    // Generate new set without stopping
    const newItems = generateExercise(settings);
    setExerciseItems(newItems);
    setCursorIndex(0);
    setSelectedChordNotes([]);
    setFeedbackMessage(null);
  };

  const stopGame = () => {
    setIsPlaying(false);
    setExerciseItems([]);
  };

  // --- Core Game Logic ---

  const handlePianoInput = useCallback((midi: number) => {
    if (!isPlaying) return;
    if (cursorIndex >= exerciseItems.length) return;

    const currentItem = exerciseItems[cursorIndex];

    if (settings.mode === 'single' || settings.mode === 'beams') {
      // Immediate evaluation
      const targetMidi = currentItem.notes[0].midi;

      if (midi === targetMidi) {
        // Correct
        const updatedItems = [...exerciseItems];
        updatedItems[cursorIndex].status = 'correct';
        setExerciseItems(updatedItems);

        // Advance
        if (cursorIndex + 1 < exerciseItems.length) {
          setCursorIndex(prev => prev + 1);
        } else {
          // End of turn, slight delay then next
          setTimeout(() => nextTurn(), 500);
        }
      } else {
        // Incorrect
        // Visual feedback?
        setFeedbackMessage('Try again!');
        setTimeout(() => setFeedbackMessage(null), 1000);
      }
    } else if (settings.mode === 'chords') {
      // Toggle selection
      setSelectedChordNotes(prev => {
        if (prev.includes(midi)) return prev.filter(n => n !== midi);
        return [...prev, midi];
      });
    }
  }, [isPlaying, cursorIndex, exerciseItems, settings.mode]);

  const submitChord = () => {
    if (cursorIndex >= exerciseItems.length) return;
    const currentItem = exerciseItems[cursorIndex];
    const targetMidis = currentItem.notes.map(n => n.midi).sort();
    const selectedSorted = [...selectedChordNotes].sort();

    // Compare arrays
    const isCorrect = JSON.stringify(targetMidis) === JSON.stringify(selectedSorted);

    if (isCorrect) {
       const updatedItems = [...exerciseItems];
       updatedItems[cursorIndex].status = 'correct';
       setExerciseItems(updatedItems);
       setSelectedChordNotes([]);

       if (cursorIndex + 1 < exerciseItems.length) {
         setCursorIndex(prev => prev + 1);
       } else {
         setTimeout(() => nextTurn(), 500);
       }
    } else {
      setFeedbackMessage('Incorrect chord notes.');
      setTimeout(() => setFeedbackMessage(null), 1000);
    }
  };

  // --- Render ---

  return (
    <div className="flex flex-col h-full bg-slate-900 text-slate-100 font-sans">

      {/* Header */}
      <header className="flex items-center justify-between px-6 py-4 bg-slate-800 border-b border-slate-700 shadow-sm z-50">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-500 rounded-lg">
            <Music className="w-6 h-6 text-white" />
          </div>
          <h1 className="text-xl font-bold tracking-wide">Virtuoso <span className="text-indigo-400 font-light">Sight Reader</span></h1>
        </div>

        {isPlaying && (
          <button 
            onClick={stopGame}
            className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-red-300 bg-red-900/30 hover:bg-red-900/50 rounded-full transition-colors"
          >
            <RotateCcw className="w-4 h-4" /> Quit Exercise
          </button>
        )}
      </header>

      {/* Main Content */}
      <main className="flex-1 flex flex-col items-center justify-center relative p-4 overflow-y-auto">

        {!isPlaying ? (
          // Menu Screen
          <div className="w-full max-w-md bg-slate-800 p-8 rounded-2xl shadow-2xl border border-slate-700">
             <div className="mb-8 text-center">
               <h2 className="text-2xl font-bold mb-2">Configuration</h2>
               <p className="text-slate-400 text-sm">Customize your practice session</p>
             </div>

             <div className="space-y-6">
                {/* Mode Selection */}
                <div className="space-y-2">
                  <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider">Mode</label>
                  <div className="grid grid-cols-3 gap-2">
                    {(['single', 'chords', 'beams'] as const).map(m => (
                      <button
                        key={m}
                        onClick={() => setSettings(prev => ({ ...prev, mode: m }))}
                        className={`py-2 px-4 rounded-lg text-sm font-medium transition-all capitalize border ${
                          settings.mode === m 
                            ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg shadow-indigo-500/30' 
                            : 'bg-slate-700 border-slate-600 text-slate-300 hover:bg-slate-600'
                        }`}
                      >
                        {m}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Clef Selection */}
                <div className="space-y-2">
                  <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider">Clef</label>
                  <div className="grid grid-cols-2 gap-2">
                    <button
                      onClick={() => setSettings(prev => ({ ...prev, clef: 'treble' }))}
                      className={`py-2 px-4 rounded-lg text-sm font-medium transition-all border ${
                        settings.clef === 'treble' 
                          ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg shadow-indigo-500/30' 
                          : 'bg-slate-700 border-slate-600 text-slate-300 hover:bg-slate-600'
                      }`}
                    >
                      Treble 🎼
                    </button>
                    <button
                      onClick={() => setSettings(prev => ({ ...prev, clef: 'bass' }))}
                      className={`py-2 px-4 rounded-lg text-sm font-medium transition-all border ${
                        settings.clef === 'bass' 
