import React, { useState, useEffect, useCallback } from 'react';
import { Music, Settings as SettingsIcon, Volume2, RotateCcw, Check, Play, Loader2 } from 'lucide-react';
import Piano from './components/Piano';
import SheetMusic from './components/SheetMusic';
import { GameSettings, ExerciseItem } from './types';
import { generateExercise } from './services/logic';
import { audioService } from './services/audioService';

const App: React.FC = () => {
  // --- State ---
  const [isPlaying, setIsPlaying] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [settings, setSettings] = useState<GameSettings>({
    clef: 'treble',
    useAccidentals: false,
    mode: 'single'
  });

  const [exerciseItems, setExerciseItems] = useState<ExerciseItem[]>([]);
  const [cursorIndex, setCursorIndex] = useState(0);
  const [selectedChordNotes, setSelectedChordNotes] = useState<number[]>([]);
  const [feedbackMessage, setFeedbackMessage] = useState<string | null>(null);

  // --- Actions ---

  const startGame = async () => {
    setIsLoading(true);
    try {
      await audioService.init();
      const newItems = generateExercise(settings);
      setExerciseItems(newItems);
      setCursorIndex(0);
      setSelectedChordNotes([]);
      setFeedbackMessage(null);
      setIsPlaying(true);
    } catch (error) {
      console.error("Failed to initialize audio:", error);
      setFeedbackMessage("Error loading sounds. Please check your connection.");
    } finally {
      setIsLoading(false);
    }
  };

  const nextTurn = () => {
    // Generate new set without stopping
    const newItems = generateExercise(settings);
    setExerciseItems(newItems);
    setCursorIndex(0);
    setSelectedChordNotes([]);
    setFeedbackMessage(null);
  };

  const stopGame = () => {
    setIsPlaying(false);
    setExerciseItems([]);
  };

  // --- Core Game Logic ---

  const handlePianoInput = useCallback((midi: number) => {
    if (!isPlaying) return;
    if (cursorIndex >= exerciseItems.length) return;

    const currentItem = exerciseItems[cursorIndex];

    if (settings.mode === 'single' || settings.mode === 'beams') {
      // Immediate evaluation
      const targetMidi = currentItem.notes[0].midi;

      if (midi === targetMidi) {
        // Correct
        const updatedItems = [...exerciseItems];
        updatedItems[cursorIndex].status = 'correct';
        setExerciseItems(updatedItems);

        // Advance
        if (cursorIndex + 1 < exerciseItems.length) {
          setCursorIndex(prev => prev + 1);
        } else {
          // End of turn, slight delay then next
          setTimeout(() => nextTurn(), 500);
        }
      } else {
        // Incorrect
        // Visual feedback?
        setFeedbackMessage('Try again!');
        setTimeout(() => setFeedbackMessage(null), 1000);
      }
    } else if (settings.mode === 'chords') {
      // Toggle selection
      setSelectedChordNotes(prev => {
        if (prev.includes(midi)) return prev.filter(n => n !== midi);
        return [...prev, midi];
      });
    }
  }, [isPlaying, cursorIndex, exerciseItems, settings.mode]);

  const submitChord = () => {
    if (cursorIndex >= exerciseItems.length) return;
    const currentItem = exerciseItems[cursorIndex];
    const targetMidis = currentItem.notes.map(n => n.midi).sort();
    const selectedSorted = [...selectedChordNotes].sort();

    // Compare arrays
    const isCorrect = JSON.stringify(targetMidis) === JSON.stringify(selectedSorted);

    if (isCorrect) {
       const updatedItems = [...exerciseItems];
       updatedItems[cursorIndex].status = 'correct';
       setExerciseItems(updatedItems);
       setSelectedChordNotes([]);

       if (cursorIndex + 1 < exerciseItems.length) {
         setCursorIndex(prev => prev + 1);
       } else {
         setTimeout(() => nextTurn(), 500);
       }
    } else {
      setFeedbackMessage('Incorrect chord notes.');
      setTimeout(() => setFeedbackMessage(null), 1000);
    }
  };

  // --- Render ---

  return (
    <div className="flex flex-col h-full bg-slate-900 text-slate-100 font-sans">

      {/* Header */}
      <header className="flex items-center justify-between px-6 py-4 bg-slate-800 border-b border-slate-700 shadow-sm z-50">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-500 rounded-lg">
            <Music className="w-6 h-6 text-white" />
          </div>
          <h1 className="text-xl font-bold tracking-wide">Virtuoso <span className="text-indigo-400 font-light">Sight Reader</span></h1>
        </div>

        {isPlaying && (
          <button 
            onClick={stopGame}
            className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-red-300 bg-red-900/30 hover:bg-red-900/50 rounded-full transition-colors"
          >
            <RotateCcw className="w-4 h-4" /> Quit Exercise
          </button>
        )}
      </header>

      {/* Main Content */}
      <main className="flex-1 flex flex-col items-center justify-center relative p-4 overflow-y-auto">

        {!isPlaying ? (
          // Menu Screen
          <div className="w-full max-w-md bg-slate-800 p-8 rounded-2xl shadow-2xl border border-slate-700">
             <div className="mb-8 text-center">
               <h2 className="text-2xl font-bold mb-2">Configuration</h2>
               <p className="text-slate-400 text-sm">Customize your practice session</p>
             </div>

             <div className="space-y-6">
                {/* Mode Selection */}
                <div className="space-y-2">
                  <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider">Mode</label>
                  <div className="grid grid-cols-3 gap-2">
                    {(['single', 'chords', 'beams'] as const).map(m => (
                      <button
                        key={m}
                        onClick={() => setSettings(prev => ({ ...prev, mode: m }))}
                        className={`py-2 px-4 rounded-lg text-sm font-medium transition-all capitalize border ${
                          settings.mode === m 
                            ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg shadow-indigo-500/30' 
                            : 'bg-slate-700 border-slate-600 text-slate-300 hover:bg-slate-600'
                        }`}
                      >
                        {m}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Clef Selection */}
                <div className="space-y-2">
                  <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider">Clef</label>
                  <div className="grid grid-cols-2 gap-2">
                    <button
                      onClick={() => setSettings(prev => ({ ...prev, clef: 'treble' }))}
                      className={`py-2 px-4 rounded-lg text-sm font-medium transition-all border ${
                        settings.clef === 'treble' 
