import React, { useEffect, useRef } from 'react';
import { Factory, Beam, Fraction } from 'vexflow';
import { ExerciseItem, ClefType } from '../types';

interface SheetMusicProps {
  items: ExerciseItem[];
  clef: ClefType;
  activeIndex: number;
}

const SheetMusic: React.FC<SheetMusicProps> = ({ items, clef, activeIndex }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current || items.length === 0) return;

    // Clear previous render
    containerRef.current.innerHTML = '';

    // Use a fixed width that is large enough, or fit to container
    const containerWidth = containerRef.current.clientWidth;

    // Scaling factor to make the music bigger
    const scale = 1.6;
    const height = 200 * scale; // Adjust height based on scale

    const vf = new Factory({
      renderer: { elementId: containerRef.current, width: containerWidth, height }
    });

    const context = vf.getContext();
    context.scale(scale, scale);

    const score = vf.EasyScore();
    const system = vf.System({
        width: (containerWidth / scale) - 10, // Adjust width to fit within scaled coordinate system
        noJustification: false 
    });

    // Convert Exercise Items to VexFlow Notes
    const staveNotes = items.flatMap((item, index) => {
      const keys = item.notes.map(n => `${n.name}${n.accidental || ''}${n.octave}`);
      const duration = item.notes[0].duration || 'q';

      let noteString = '';
      if (keys.length > 1) {
        noteString = `(${keys.join(' ')})/${duration}`;
      } else {
        noteString = `${keys[0]}/${duration}`;
      }

      const isActive = index === activeIndex;
      const color = item.status === 'correct' ? '#22c55e' : 
                    item.status === 'incorrect' ? '#ef4444' : 
                    isActive ? '#3b82f6' : 'black';

      const notes = score.notes(noteString, { stem: 'up', clef });

      notes.forEach(note => {
         note.setStyle({ fillStyle: color, strokeStyle: color });
      });

      return notes;
    });

    const durationValues: Record<string, number> = {
      'w': 4, 'h': 2, 'q': 1, '8': 0.5, '16': 0.25
    };

    const totalBeats = items.reduce((acc, item) => {
      const dur = item.notes[0].duration || 'q';
      return acc + (durationValues[dur] || 1); 
    }, 0);

    let numBeats = totalBeats;
    let beatValue = 4;

    if (totalBeats % 1 !== 0) {
      if (totalBeats % 0.5 === 0) {
        numBeats = totalBeats * 2;
        beatValue = 8;
      } else {
        numBeats = totalBeats * 4;
        beatValue = 16;
      }
    }

    const timeSig = `${numBeats}/${beatValue}`;
    const voice = score.voice(staveNotes, { time: timeSig });

    const beams = Beam.generateBeams(staveNotes, {
        groups: [new Fraction(2, 4)] 
    });

    const stave = system.addStave({
      voices: [voice]
    });

    stave.addClef(clef);
    stave.addTimeSignature(timeSig);

    vf.draw();

    beams.forEach(b => b.setContext(vf.getContext()).draw());

  }, [items, clef, activeIndex]);

  return (
    <div className="w-full flex justify-center bg-white rounded-xl shadow-inner p-4 overflow-hidden mb-6">
       <div ref={containerRef} className="w-full" /> 
    </div>
  );
};

