import { Note, ExerciseItem, GameSettings, KeyRoot, KeyType } from '../types';
import { v4 as uuidv4 } from 'uuid';

// Keyboard constraint: F1 (29) to E6 (88)
const TREBLE_MIN = 53; // F3
const TREBLE_MAX = 88; // E6
const BASS_MIN = 29;   // F1
const BASS_MAX = 67;   // G4

const getRandomInt = (min: number, max: number) => {
  return Math.floor(Math.random() * (max - min + 1)) + min;
};

// --- Key Signature Logic ---

// Offsets from C (0) for each root note
const ROOT_OFFSETS: Record<KeyRoot, number> = {
  'C': 0, 'D': 2, 'E': 4, 'F': 5, 'G': 7, 'A': 9, 'B': 11
};

// Scale Intervals (semitones)
const MAJOR_INTERVALS = [0, 2, 4, 5, 7, 9, 11];
const MINOR_INTERVALS = [0, 2, 3, 5, 7, 8, 10]; // Natural Minor

// Helper to check if a pitch class (0-11) is in the scale
const getScalePitchClasses = (root: KeyRoot, type: KeyType): number[] => {
  const rootMidi = ROOT_OFFSETS[root];
  const intervals = type === 'major' ? MAJOR_INTERVALS : MINOR_INTERVALS;
  return intervals.map(interval => (rootMidi + interval) % 12);
};

// Determine preference for Sharps vs Flats based on Key
// Flat keys: F Major, d minor, Bb Major (not in list), etc.
// From our list (C,D,E,F,G,A,B):
// F Major (1b), D Minor (1b), G Minor (2b), C Minor (3b), F Minor (4b).
// All others generally use Sharps (or C Maj / A Min which are neutral but favor sharp for accidentals usually).
const shouldUseFlats = (root: KeyRoot, type: KeyType): boolean => {
  if (root === 'F' && type === 'major') return true;
  if (['D', 'G', 'C', 'F'].includes(root) && type === 'minor') return true;
  return false;
};

const NOTE_NAMES_SHARP = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];
const NOTE_NAMES_FLAT  = ['C', 'Db', 'D', 'Eb', 'E', 'F', 'Gb', 'G', 'Ab', 'A', 'Bb', 'B'];

const midiToNote = (midi: number, root: KeyRoot, type: KeyType): Note => {
  const octave = Math.floor(midi / 12) - 1;
  const pitchClass = midi % 12;
  const useFlats = shouldUseFlats(root, type);

  const rawName = useFlats ? NOTE_NAMES_FLAT[pitchClass] : NOTE_NAMES_SHARP[pitchClass];

  let name = rawName;
  let accidental: '#' | 'b' | 'n' | null = null;

  if (rawName.includes('#')) {
    name = rawName[0];
    accidental = '#';
  } else if (rawName.includes('b')) {
    name = rawName[0];
    accidental = 'b';
  } else {
    // It's a natural note name (C, D, E...)
    // However, if we are in a key signature, we need to check if this "natural" name
    // actually contradicts the key signature (e.g., F natural in G Major).
    // VexFlow handles the key signature context. If we say "F" in G Major, VexFlow renders F natural with a natural sign.
    // If we mean F# (which is in key), we must pass "F#" to VexFlow.
    // Our logic above picked the name based on chromatic pitch.
    // Example: G Major (F#). Input MIDI 66 (F#).
    // useFlats = false. rawName = "F#". name="F", accidental="#".
    // VexFlow logic: Key "G". Note "F#". It will render note on F line, NO accidental shown. Correct.

    // Example: G Major. Input MIDI 65 (F Natural).
    // useFlats = false. rawName = "F". name="F", accidental=null.
    // VexFlow logic: Key "G". Note "F". It will render note on F line, WITH natural symbol. Correct.
  }

  return {
    midi,
    name,
    octave,
    accidental
  };
};

export const generateExercise = (settings: GameSettings): ExerciseItem[] => {
  const items: ExerciseItem[] = [];
  const min = settings.clef === 'treble' ? TREBLE_MIN : BASS_MIN;
  const max = settings.clef === 'treble' ? TREBLE_MAX : BASS_MAX;
  const itemCount = 6;

  // 1. Determine allowed pitch classes based on Key Signature
  const allowedPitchClasses = getScalePitchClasses(settings.keyRoot, settings.keyType);

  // Helper to check validity
  const isValidNote = (midi: number): boolean => {
    // If useAccidentals is FALSE, note MUST be in scale
    if (!settings.useAccidentals) {
      return allowedPitchClasses.includes(midi % 12);
    }
    return true; // If true, any chromatic note is allowed
  };

  const getValidRandomMidi = (min: number, max: number): number => {
    let midi = getRandomInt(min, max);
    // Try to find a valid note. To avoid infinite loops, we just search nearby if invalid.
    if (!isValidNote(midi)) {
      // If we need strict scale notes, scan up/down to find nearest
      let up = midi;
      let down = midi;
      while (true) {
        if (up <= max && isValidNote(up)) return up;
        if (down >= min && isValidNote(down)) return down;
        up++;
        down--;
        if (up > max && down < min) return midi; // Should not happen given ranges
      }
    }
    return midi;
  };

  if (settings.mode === 'single') {
    for (let i = 0; i < itemCount; i++) {
      const midi = getValidRandomMidi(min, max);
      items.push({
        id: uuidv4(),
        notes: [midiToNote(midi, settings.keyRoot, settings.keyType)],
        status: 'pending'
      });
    }
  } 
  else if (settings.mode === 'chords') {
    for (let i = 0; i < itemCount; i++) {
      // Chords need more complex validation logic to ensure the root and intervals make sense
      // For now, let's pick a root valid in the scale, then build a chord.

      const safeMax = max - 11;
      let root = getValidRandomMidi(min, safeMax);

      const isSeventh = Math.random() > 0.7;
      const chordMidis = [root];

      // Basic Triad Construction
      // We want to build chords that generally sound "in key" if accidentals are off,
      // or "jazzy" if on.
      // Simple strategy: Pick major/minor third and fifth.

      // To adhere strictly to key signature (diatonic chords):
      if (!settings.useAccidentals) {
         // Diatonic stacking: find the 3rd and 5th scale degrees relative to this root
         // This is complex to calculate dynamically. 
         // Simpler: Pick 3 semitones (min3) or 4 (Maj3), check if result is in scale.

         const possibleThirds = [3, 4];
         const validThird = possibleThirds.find(interval => allowedPitchClasses.includes((root + interval) % 12));

         if (validThird === undefined) { i--; continue; } // Retry
         chordMidis.push(root + validThird);

         const possibleFifths = [6, 7, 8]; // Dim, Perf, Aug
         const validFifth = possibleFifths.find(interval => allowedPitchClasses.includes((root + interval) % 12));

         if (validFifth === undefined) { i--; continue; }
         chordMidis.push(root + validFifth);

         if (isSeventh) {
             const possibleSevenths = [10, 11]; // min7, maj7
             const validSeventh = possibleSevenths.find(interval => allowedPitchClasses.includes((root + interval) % 12));
             if (validSeventh) chordMidis.push(root + validSeventh);
         }
      } else {
        // Free chromatic construction
        const third = Math.random() > 0.5 ? 4 : 3; 
        chordMidis.push(root + third);
        chordMidis.push(root + 7); // Perfect fifth default
        if (isSeventh) {
            chordMidis.push(root + 10 + (Math.random() > 0.5 ? 1 : 0));
        }
      }

      const finalNotes = chordMidis.map(m => midiToNote(m, settings.keyRoot, settings.keyType)); 

      items.push({
        id: uuidv4(),
        notes: finalNotes,
        status: 'pending'
      });
    }
  }
  else if (settings.mode === 'beams') {
    for (let i = 0; i < itemCount; i++) {
      const midi = getValidRandomMidi(min, max);
      const duration = Math.random() > 0.5 ? '8' : '16';

      const note = midiToNote(midi, settings.keyRoot, settings.keyType);
      note.duration = duration;

      items.push({
        id: uuidv4(),
        notes: [note],
        status: 'pending',
        isBeamGroup: true
      });
    }
  }

  return items;
};

