import { Note, ExerciseItem, GameSettings, KeyRoot, KeyType } from '../types';
import { v4 as uuidv4 } from 'uuid';

// Keyboard constraint: F1 (29) to E6 (88)
const TREBLE_MIN = 53; // F3
const TREBLE_MAX = 88; // E6
const BASS_MIN = 29;   // F1
const BASS_MAX = 67;   // G4

const getRandomInt = (min: number, max: number) => {
  return Math.floor(Math.random() * (max - min + 1)) + min;
};

// --- Key Signature Logic ---

// Offsets from C (0) for each root note
const ROOT_OFFSETS: Record<KeyRoot, number> = {
  'C': 0, 'D': 2, 'E': 4, 'F': 5, 'G': 7, 'A': 9, 'B': 11
};

// Scale Intervals (semitones)
const MAJOR_INTERVALS = [0, 2, 4, 5, 7, 9, 11];
const MINOR_INTERVALS = [0, 2, 3, 5, 7, 8, 10]; // Natural Minor

// Helper to check if a pitch class (0-11) is in the scale
const getScalePitchClasses = (root: KeyRoot, type: KeyType): number[] => {
  const rootMidi = ROOT_OFFSETS[root];
  const intervals = type === 'major' ? MAJOR_INTERVALS : MINOR_INTERVALS;
  return intervals.map(interval => (rootMidi + interval) % 12);
};

// Determine preference for Sharps vs Flats based on Key
const shouldUseFlats = (root: KeyRoot, type: KeyType): boolean => {
  if (root === 'F' && type === 'major') return true;
  if (['D', 'G', 'C', 'F'].includes(root) && type === 'minor') return true;
  return false;
};

const NOTE_NAMES_SHARP = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];
const NOTE_NAMES_FLAT  = ['C', 'Db', 'D', 'Eb', 'E', 'F', 'Gb', 'G', 'Ab', 'A', 'Bb', 'B'];

const midiToNote = (midi: number, root: KeyRoot, type: KeyType): Note => {
  const octave = Math.floor(midi / 12) - 1;
  const pitchClass = midi % 12;
  const useFlats = shouldUseFlats(root, type);

  const rawName = useFlats ? NOTE_NAMES_FLAT[pitchClass] : NOTE_NAMES_SHARP[pitchClass];

  let name = rawName;
  let accidental: '#' | 'b' | 'n' | null = null;

  if (rawName.includes('#')) {
    name = rawName[0];
    accidental = '#';
  } else if (rawName.includes('b')) {
    name = rawName[0];
    accidental = 'b';
  }

  return {
    midi,
    name,
    octave,
    accidental
  };
};

export const generateExercise = (settings: GameSettings): ExerciseItem[] => {
  const items: ExerciseItem[] = [];
  const min = settings.clef === 'treble' ? TREBLE_MIN : BASS_MIN;
  const max = settings.clef === 'treble' ? TREBLE_MAX : BASS_MAX;

  // 1. Determine allowed pitch classes based on Key Signature
  const allowedPitchClasses = getScalePitchClasses(settings.keyRoot, settings.keyType);

  // Helper to check validity
  const isValidNote = (midi: number): boolean => {
    // If useAccidentals is FALSE, note MUST be in scale
    if (!settings.useAccidentals) {
      return allowedPitchClasses.includes(midi % 12);
    }
    return true; 
  };

  const getValidRandomMidi = (min: number, max: number): number => {
    let midi = getRandomInt(min, max);
    if (!isValidNote(midi)) {
      let up = midi;
      let down = midi;
      while (true) {
        if (up <= max && isValidNote(up)) return up;
        if (down >= min && isValidNote(down)) return down;
        up++;
        down--;
        if (up > max && down < min) return midi;
      }
    }
    return midi;
  };

  if (settings.mode === 'single') {
    const itemCount = 6;
    for (let i = 0; i < itemCount; i++) {
      const midi = getValidRandomMidi(min, max);
      items.push({
        id: uuidv4(),
        notes: [midiToNote(midi, settings.keyRoot, settings.keyType)],
        status: 'pending'
      });
    }
  } 
  else if (settings.mode === 'chords') {
    const itemCount = 6;
    for (let i = 0; i < itemCount; i++) {
      const safeMax = max - 11;
      let root = getValidRandomMidi(min, safeMax);

      const isSeventh = Math.random() > 0.7;
      const chordMidis = [root];

      if (!settings.useAccidentals) {
         const possibleThirds = [3, 4];
         const validThird = possibleThirds.find(interval => allowedPitchClasses.includes((root + interval) % 12));

         if (validThird === undefined) { i--; continue; } 
         chordMidis.push(root + validThird);

         const possibleFifths = [6, 7, 8]; 
         const validFifth = possibleFifths.find(interval => allowedPitchClasses.includes((root + interval) % 12));

         if (validFifth === undefined) { i--; continue; }
         chordMidis.push(root + validFifth);

         if (isSeventh) {
             const possibleSevenths = [10, 11]; 
             const validSeventh = possibleSevenths.find(interval => allowedPitchClasses.includes((root + interval) % 12));
             if (validSeventh) chordMidis.push(root + validSeventh);
         }
      } else {
        const third = Math.random() > 0.5 ? 4 : 3; 
        chordMidis.push(root + third);
        chordMidis.push(root + 7); 
        if (isSeventh) {
            chordMidis.push(root + 10 + (Math.random() > 0.5 ? 1 : 0));
        }
      }

      const finalNotes = chordMidis.map(m => midiToNote(m, settings.keyRoot, settings.keyType)); 

      items.push({
        id: uuidv4(),
        notes: finalNotes,
        status: 'pending'
      });
    }
  }
  else if (settings.mode === 'beams') {
    // Generate 3-4 groups, each with 4-6 notes
    const numGroups = getRandomInt(3, 4);
    let currentBeamIndex = 0;

    for (let g = 0; g < numGroups; g++) {
        const groupSize = getRandomInt(4, 6);
        // Using 16th notes (semiquavers) for beam mode to create dense, fast-looking groups
        const duration = '16'; 

        for (let n = 0; n < groupSize; n++) {
            const midi = getValidRandomMidi(min, max);
            const note = midiToNote(midi, settings.keyRoot, settings.keyType);
            note.duration = duration;

            items.push({
                id: uuidv4(),
                notes: [note],
                status: 'pending',
                isBeamGroup: true,
                beamGroupIndex: currentBeamIndex
            });
        }
        currentBeamIndex++;
    }
  }

  return items;
};

import React, { useEffect, useRef } from 'react';
import { Factory, Beam } from 'vexflow';
import { ExerciseItem, ClefType, KeyRoot, KeyType } from '../types';

interface SheetMusicProps {
  items: ExerciseItem[];
  clef: ClefType;
  activeIndex: number;
  keyRoot?: KeyRoot;
  keyType?: KeyType;
}

const SheetMusic: React.FC<SheetMusicProps> = ({ 
  items, 
  clef, 
  activeIndex, 
  keyRoot = 'C', 
  keyType = 'major' 
}) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current || items.length === 0) return;

    // Clear previous render
    containerRef.current.innerHTML = '';

    const containerClientWidth = containerRef.current.clientWidth;

    // Scaling factor to make the music bigger
    const scale = 1.6;
    const height = 200 * scale; 

    // Determine width to ensure notes are not cramped.
    // For beams, we can reduce note width slightly as they are grouped, but keeping large ensures clarity.
    const minWidthPerNote = 100; 
    // Add extra width for Key Signature rendering at the start
    const minSystemWidth = items.length * minWidthPerNote + 50; 

    const availableSystemWidth = (containerClientWidth / scale) - 20; 
    const systemWidth = Math.max(availableSystemWidth, minSystemWidth);

    const factoryWidth = systemWidth * scale + 20; 

    const vf = new Factory({
      renderer: { elementId: containerRef.current, width: factoryWidth, height }
    });

    const context = vf.getContext();
    context.scale(scale, scale);

    const score = vf.EasyScore();
    const system = vf.System({
        width: systemWidth, 
        noJustification: false 
    });

    // Convert Exercise Items to VexFlow Notes
    const staveNotes = items.flatMap((item, index) => {
      const keys = item.notes.map(n => `${n.name}${n.accidental || ''}${n.octave}`);
      const duration = item.notes[0].duration || 'q';

      let noteString = '';
      if (keys.length > 1) {
        noteString = `(${keys.join(' ')})/${duration}`;
      } else {
        noteString = `${keys[0]}/${duration}`;
      }

      const isActive = index === activeIndex;
      const color = item.status === 'correct' ? '#22c55e' : 
                    item.status === 'incorrect' ? '#ef4444' : 
                    isActive ? '#3b82f6' : 'black';

      // Pass clef here so VexFlow auto-calculates positions correctly
      const notes = score.notes(noteString, { stem: 'up', clef });

      notes.forEach(note => {
         note.setStyle({ fillStyle: color, strokeStyle: color });
      });

      return notes;
    });

    const durationValues: Record<string, number> = {
      'w': 4, 'h': 2, 'q': 1, '8': 0.5, '16': 0.25
    };

    const totalBeats = items.reduce((acc, item) => {
      const dur = item.notes[0].duration || 'q';
      return acc + (durationValues[dur] || 1); 
    }, 0);

    let numBeats = totalBeats;
    let beatValue = 4;

    // Adjust Time Signature based on fractional beats
    // This supports e.g., 15/16 time signature if we have odd groupings
    if (totalBeats % 1 !== 0) {
      if (totalBeats % 0.5 === 0) {
        numBeats = totalBeats * 2;
        beatValue = 8;
      } else {
        numBeats = totalBeats * 4;
        beatValue = 16;
      }
    }

    if (numBeats === 0) numBeats = 4;

    const timeSig = `${numBeats}/${beatValue}`;
    const voice = score.voice(staveNotes, { time: timeSig });

    // Manual Beaming based on beamGroupIndex
    const beams: Beam[] = [];
    let currentBeamGroup: any[] = [];
    let lastBeamIndex = -1;

    // staveNotes and items map 1:1 because chords are single items in items array and single notes in staveNotes array
    staveNotes.forEach((note, index) => {
        const item = items[index];
        if (item.beamGroupIndex !== undefined) {
             if (item.beamGroupIndex !== lastBeamIndex) {
                 if (currentBeamGroup.length > 0) {
                     beams.push(new Beam(currentBeamGroup));
                 }
                 currentBeamGroup = [];
                 lastBeamIndex = item.beamGroupIndex;
             }
             currentBeamGroup.push(note);
        } else {
             // If we encounter a note without a beam group, close the previous beam
             if (currentBeamGroup.length > 0) {
                 beams.push(new Beam(currentBeamGroup));
                 currentBeamGroup = [];
             }
             lastBeamIndex = -1;
        }
    });
    // Close pending beam
    if (currentBeamGroup.length > 0) {
        beams.push(new Beam(currentBeamGroup));
    }

    const stave = system.addStave({
      voices: [voice]
    });

    stave.addClef(clef);

    // Key Signature
    let keySpec = keyRoot;
    if (keyType === 'minor') {
        keySpec += 'm';
    }
    stave.addKeySignature(keySpec);

    stave.addTimeSignature(timeSig);

    vf.draw();

    beams.forEach(b => b.setContext(vf.getContext()).draw());

  }, [items, clef, activeIndex, keyRoot, keyType]);

  return (
    <div className="w-full flex justify-center bg-white rounded-xl shadow-inner p-4 overflow-x-auto mb-6 custom-scrollbar">
       <div ref={containerRef} className="flex-shrink-0" /> 
    </div>
  );
};

