                            ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg' 
                            : 'bg-slate-700 border-slate-600 text-slate-300 hover:bg-slate-600'
                        }`}
                      >
                        Bass 𝄢
                      </button>
                    </div>
                  </div>

                  {/* Accidentals */}
                  <div className="space-y-2">
                    <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider">Options</label>
                     <div 
                       onClick={() => setSettings(prev => ({ ...prev, useAccidentals: !prev.useAccidentals }))}
                       className="cursor-pointer flex items-center justify-between p-2 bg-slate-700 rounded-lg border border-slate-600 hover:bg-slate-650 transition-colors h-[42px]"
                     >
                      <span className="text-xs font-medium pl-1">Chromatics</span>
                      <div className={`w-8 h-4 rounded-full relative transition-colors ${settings.useAccidentals ? 'bg-indigo-500' : 'bg-slate-500'}`}>
                         <div className={`absolute top-0.5 w-3 h-3 bg-white rounded-full transition-all ${settings.useAccidentals ? 'left-4.5' : 'left-0.5'}`} style={{ left: settings.useAccidentals ? '18px' : '2px' }}/>
                      </div>
                    </div>
                    <div className="text-[10px] text-slate-500 leading-tight px-1">
                        {settings.useAccidentals ? "Allows notes outside the key signature." : "Strictly notes within key signature."}
                    </div>
                  </div>
                </div>

