                <div className="space-y-2">
                  <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider">Key Signature</label>
                  <div className="p-3 bg-slate-700/30 rounded-lg border border-slate-700 space-y-3">

                    {/* Key Types */}
                    <div className="flex gap-2 mb-2">
                      {(['major', 'minor'] as const).map(type => (
                         <button
                           key={type}
                           onClick={() => setSettings(prev => ({ ...prev, keyType: type }))}
                           className={`flex-1 py-1.5 rounded-md text-xs font-bold uppercase tracking-wide transition-all border ${
                             settings.keyType === type
