import React, { useEffect, useRef } from 'react';
import { Factory, Beam } from 'vexflow';
import { ExerciseItem, ClefType, KeyRoot, KeyType } from '../types';

interface SheetMusicProps {
  items: ExerciseItem[];
  clef: ClefType;
  activeIndex: number;
  keyRoot?: KeyRoot;
  keyType?: KeyType;
}

const SheetMusic: React.FC<SheetMusicProps> = ({ 
  items, 
  clef, 
  activeIndex, 
  keyRoot = 'C', 
  keyType = 'major' 
}) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current || items.length === 0) return;

    // Clear previous render
    containerRef.current.innerHTML = '';

    const containerClientWidth = containerRef.current.clientWidth;

    // Scaling factor to make the music bigger
    const scale = 1.6;
    const height = 200 * scale; 

    // Calculate required width based on content dynamically
    let calculatedMinWidth = 80; // Base padding for Key/Clef/TimeSig

    items.forEach((item, index) => {
        const isBeamed = item.isBeamGroup;
        const prevItem = items[index - 1];

        // Add extra space if starting a new beam group
        const isNewGroup = isBeamed && prevItem && prevItem.beamGroupIndex !== item.beamGroupIndex;
        if (isNewGroup) {
            calculatedMinWidth += 40; // Larger gap between beam groups for clear separation
        }

        // Dynamic width calculation
        let itemWidth = 100; // Default for single notes/chords

        if (isBeamed) {
            itemWidth = 22; // Very tight base spacing for beams
            // Add extra breathing room if there's an accidental to prevent collision
            if (item.notes.some(n => n.accidental)) {
                itemWidth += 14; 
            }
        }

        calculatedMinWidth += itemWidth; 
    });

    // Ensure we don't shrink below a reasonable minimum
    const minSystemWidth = Math.max(calculatedMinWidth, 400); 

    // Use the calculated width directly to avoid stretching notes apart on wide screens.
    // If it's wider than the container, overflow-x-auto handles scrolling.
    // If it's narrower, the parent flex container centers it.
    const systemWidth = minSystemWidth;

    // The canvas/SVG width must accommodate the scaled system
    const factoryWidth = systemWidth * scale + 40; // +40 buffer

    const vf = new Factory({
      renderer: { elementId: containerRef.current, width: factoryWidth, height }
    });

    const context = vf.getContext();
    context.scale(scale, scale);

    const score = vf.EasyScore();
    const system = vf.System({
        x: 0,
        y: 50, // Added vertical offset to prevent high notes/ledger lines from being cut off
        width: systemWidth, 
        noJustification: false 
    });

    // Convert Exercise Items to VexFlow Notes
    const staveNotes = items.flatMap((item, index) => {
      // Logic for note string construction:
      // We explicitly pass the accidental if it exists in the note object.
      // However, EasyScore + KeySignature is smart.
      // If we are in D Major, and pass 'F#4', it renders F on the top line WITHOUT a sharp symbol.
      // If we pass 'F4' (natural) in D Major, we should ideally pass 'Fn4' for explicit natural.

      const keys = item.notes.map(n => {
          let acc = n.accidental || '';
          // VexFlow EasyScore uses 'n' for natural, '#' for sharp, 'b' for flat.
          // n.accidental already matches this format generally.
          return `${n.name}${acc}${n.octave}`;
      });

      const duration = item.notes[0].duration || 'q';

      let noteString = '';
      if (keys.length > 1) {
        noteString = `(${keys.join(' ')})/${duration}`;
      } else {
        noteString = `${keys[0]}/${duration}`;
      }

      const isActive = index === activeIndex;
      const color = item.status === 'correct' ? '#22c55e' : 
                    item.status === 'incorrect' ? '#ef4444' : 
                    isActive ? '#3b82f6' : 'black';

      // Pass clef here so VexFlow auto-calculates positions correctly
      const notes = score.notes(noteString, { stem: 'up', clef });

      notes.forEach(note => {
         note.setStyle({ fillStyle: color, strokeStyle: color });
      });

      return notes;
    });

    const durationValues: Record<string, number> = {
      'w': 4, 'h': 2, 'q': 1, '8': 0.5, '16': 0.25
    };

    const totalBeats = items.reduce((acc, item) => {
      const dur = item.notes[0].duration || 'q';
      return acc + (durationValues[dur] || 1); 
    }, 0);

    let numBeats = totalBeats;
    let beatValue = 4;

    if (totalBeats % 1 !== 0) {
      if (totalBeats % 0.5 === 0) {
        numBeats = totalBeats * 2;
        beatValue = 8;
      } else {
        numBeats = totalBeats * 4;
        beatValue = 16;
      }
    }

    if (numBeats === 0) numBeats = 4;

    const timeSig = `${numBeats}/${beatValue}`;
    const voice = score.voice(staveNotes, { time: timeSig });

    // Manual Beaming based on beamGroupIndex
    const beams: Beam[] = [];
    let currentBeamGroup: any[] = [];
    let lastBeamIndex: number | undefined = undefined;

    staveNotes.forEach((note, index) => {
        const item = items[index];
        if (item.beamGroupIndex !== undefined) {
             // If we are in a new group (different index than last one), close previous
             if (lastBeamIndex !== undefined && item.beamGroupIndex !== lastBeamIndex) {
                 if (currentBeamGroup.length > 0) {
                     beams.push(new Beam(currentBeamGroup));
                 }
                 currentBeamGroup = [];
             }

             currentBeamGroup.push(note);
             lastBeamIndex = item.beamGroupIndex;
        } else {
             // Not in a beam group. Close any existing group.
             if (currentBeamGroup.length > 0) {
                 beams.push(new Beam(currentBeamGroup));
                 currentBeamGroup = [];
             }
             lastBeamIndex = undefined;
        }
    });
    // Close pending beam
    if (currentBeamGroup.length > 0) {
        beams.push(new Beam(currentBeamGroup));
    }

    const stave = system.addStave({
      voices: [voice]
    });

    stave.addClef(clef);

    // Key Signature Construction
    let keySpec = keyRoot;
    if (keyType === 'minor') {
        keySpec += 'm';
    }
    // VexFlow handles "C#", "Bb", "F#m" etc correctly.
    stave.addKeySignature(keySpec);

    stave.addTimeSignature(timeSig);

    vf.draw();

    beams.forEach(b => b.setContext(vf.getContext()).draw());

  }, [items, clef, activeIndex, keyRoot, keyType]);

  return (
    <div className="w-full flex justify-center bg-white rounded-xl shadow-inner p-4 overflow-x-auto mb-6 custom-scrollbar">
       <div ref={containerRef} className="flex-shrink-0" /> 
    </div>
  );
};

