import React, { useEffect, useState } from 'react';
import { KEYBOARD_MAP, MIDDLE_C } from '../constants';
import { audioService } from '../services/audioService';
import { KeyConfig } from '../types';

interface PianoProps {
  onNotePlay: (midi: number) => void;
  onNoteStop?: (midi: number) => void;
  activeNotes: number[]; // Notes generated by system
  selectedNotes: number[]; // Notes currently held by user
  showLabels?: boolean;
  isDarkMode?: boolean;
}

const Piano: React.FC<PianoProps> = ({ onNotePlay, onNoteStop, selectedNotes, showLabels, isDarkMode }) => {
  const [pressedKeys, setPressedKeys] = useState<Set<number>>(new Set());

  const handleMouseDown = (midi: number) => {
    if (!pressedKeys.has(midi)) {
      audioService.startNote(midi);
      onNotePlay(midi);
      setPressedKeys(prev => new Set(prev).add(midi));
    }
  };

  const handleMouseUp = (midi: number) => {
    if (pressedKeys.has(midi)) {
      audioService.stopNote(midi);
      if (onNoteStop) onNoteStop(midi);
      setPressedKeys(prev => {
        const next = new Set(prev);
        next.delete(midi);
        return next;
      });
    }
  };

  useEffect(() => {
    const handleGlobalUp = () => {
      pressedKeys.forEach(midi => {
        audioService.stopNote(midi);
        if (onNoteStop) onNoteStop(midi);
      });
      setPressedKeys(new Set());
    };
    window.addEventListener('mouseup', handleGlobalUp);
    return () => window.removeEventListener('mouseup', handleGlobalUp);
  }, [pressedKeys, onNoteStop]);

  const whiteKeys = KEYBOARD_MAP.filter(k => k.type === 'white');
  const blackKeys = KEYBOARD_MAP.filter(k => k.type === 'black');

  const wkWidth = 100 / whiteKeys.length;

  return (
    // Removed overflow-x-auto to prevent scrolling
    <div className="w-full pb-4">
      {/* 
        Piano Container
        In Light Mode: Slightly lighter body but still dark enough to look like a piano.
        In Dark Mode: Slate 800
      */}
      <div className="relative h-64 md:h-96 bg-slate-800 dark:bg-slate-800 rounded-lg overflow-hidden select-none shadow-2xl border-t-8 border-slate-900 dark:border-slate-900 w-full ring-4 ring-slate-200 dark:ring-transparent">

        {/* White Keys Container */}
        <div className="flex w-full h-full">
          {whiteKeys.map((key) => {
              const isSelected = selectedNotes.includes(key.midi);
              const isPressed = pressedKeys.has(key.midi);

              return (
                <div
                  key={key.midi}
                  onMouseDown={() => handleMouseDown(key.midi)}
                  onMouseEnter={(e) => { if(e.buttons === 1) handleMouseDown(key.midi) }}
                  onMouseLeave={() => handleMouseUp(key.midi)}
                  className={`
                    relative h-full border-r border-slate-300 last:border-r-0 z-10 cursor-pointer
                    transition-colors duration-75
                    ${isSelected ? 'bg-blue-300' : isPressed ? 'bg-gray-200' : 'bg-white'}
                    active:bg-gray-300
                    rounded-b-md
                  `}
                  style={{ width: `${wkWidth}%` }}
                >
                  {key.midi === MIDDLE_C && (
                    <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-xs text-slate-400 font-bold">C4</div>
                  )}
                </div>
              );
          })}
        </div>

        {/* Black Keys Container (Overlay) */}
        <div className="absolute top-0 left-0 w-full h-3/5 pointer-events-none">
           {blackKeys.map((key) => {
              const previousWhiteIndex = whiteKeys.findIndex(wk => wk.midi === key.midi - 1);
              if (previousWhiteIndex === -1) return null;

              const leftPercent = (previousWhiteIndex + 1) * wkWidth - (wkWidth * 0.3); // roughly centered on border

              const isSelected = selectedNotes.includes(key.midi);
              const isPressed = pressedKeys.has(key.midi);

              return (
                <div
                  key={key.midi}
                  className="absolute h-full pointer-events-auto z-20"
                  style={{ 
                    left: `${leftPercent}%`, 
                    width: `${wkWidth * 0.6}%` 
                  }}
                >
                  <div 
                    onMouseDown={() => handleMouseDown(key.midi)}
                    onMouseEnter={(e) => { if(e.buttons === 1) handleMouseDown(key.midi) }}
                    onMouseLeave={() => handleMouseUp(key.midi)}
                    className={`
                      w-full h-full rounded-b-md cursor-pointer border-x border-b border-black shadow-md
                      transition-colors duration-75
                      ${isSelected ? 'bg-blue-600' : isPressed ? 'bg-slate-700' : 'bg-piano-black'}
                    `}
                  />
                </div>
              );
           })}
        </div>
      </div>
    </div>
  );
};

export default Piano;

import React, { useEffect, useRef } from 'react';
import { Factory, Beam, Accidental } from 'vexflow';
import { ExerciseItem, ClefType, KeyRoot, KeyType } from '../types';

interface SheetMusicProps {
  items: ExerciseItem[];
  clef: ClefType;
  activeIndex: number;
  keyRoot?: KeyRoot;
  keyType?: KeyType;
}

const SheetMusic: React.FC<SheetMusicProps> = ({ 
  items, 
  clef, 
  activeIndex, 
  keyRoot = 'C', 
  keyType = 'major' 
}) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current || items.length === 0) return;

    // Clear previous render
    containerRef.current.innerHTML = '';

    // Scaling factor to make the music bigger
    const scale = 1.6;
    const height = 200 * scale; 

    // Key spec for VexFlow (e.g., 'C', 'Dm', 'F#')
    let keySpec = keyRoot;
    if (keyType === 'minor') {
        keySpec += 'm';
    }

    // Calculate required width based on content dynamically
    let calculatedMinWidth = 80; // Base padding for Key/Clef/TimeSig

    items.forEach((item, index) => {
        const isBeamed = item.isBeamGroup;
        const prevItem = items[index - 1];

        // Add extra space if starting a new beam group
        const isNewGroup = isBeamed && prevItem && prevItem.beamGroupIndex !== item.beamGroupIndex;
        if (isNewGroup) {
            calculatedMinWidth += 40; // Larger gap between beam groups
        }

        // Dynamic width calculation
        let itemWidth = 100; // Default

        if (isBeamed) {
            itemWidth = 22; // Tight spacing
            // Heuristic: Add padding if accidental is present.
            // Ideally we check if it's redundant with key sig, but checking existence is safe buffer.
            if (item.notes.some(n => n.accidental)) {
                itemWidth += 14; 
            }
        }
        calculatedMinWidth += itemWidth; 
    });

    const minSystemWidth = Math.max(calculatedMinWidth, 400); 
    const systemWidth = minSystemWidth;
    const factoryWidth = systemWidth * scale + 40; 

    const vf = new Factory({
      renderer: { elementId: containerRef.current as any, width: factoryWidth, height }
    });

    const context = vf.getContext();
    context.scale(scale, scale);

    const score = vf.EasyScore();
    const system = vf.System({
        x: 0,
        y: 50,
        width: systemWidth, 
        noJustification: false 
    });

    const staveNotes = items.flatMap((item, index) => {
      const keys = item.notes.map(n => {
          let acc = n.accidental || '';
          return `${n.name}${acc}${n.octave}`;
      });

      const duration = item.notes[0].duration || 'q';

      let noteString = '';
      if (keys.length > 1) {
        noteString = `(${keys.join(' ')})/${duration}`;
      } else {
        noteString = `${keys[0]}/${duration}`;
      }

      const isActive = index === activeIndex;
      const color = item.status === 'correct' ? '#22c55e' : 
                    item.status === 'incorrect' ? '#ef4444' : 
                    isActive ? '#3b82f6' : 'black';

      // Pass clef to constructor or via EasyScore context if needed, but 'clef' prop in notes() handles mapping
      const notes = score.notes(noteString, { stem: 'up', clef });

      notes.forEach(note => {
         note.setStyle({ fillStyle: color, strokeStyle: color });
      });

      return notes;
    });

    const durationValues: Record<string, number> = {
      'w': 4, 'h': 2, 'q': 1, '8': 0.5, '16': 0.25
    };

    const totalBeats = items.reduce((acc, item) => {
      const dur = item.notes[0].duration || 'q';
      return acc + (durationValues[dur] || 1); 
    }, 0);

    let numBeats = totalBeats;
    let beatValue = 4;

    if (totalBeats % 1 !== 0) {
      if (totalBeats % 0.5 === 0) {
        numBeats = totalBeats * 2;
        beatValue = 8;
      } else {
        numBeats = totalBeats * 4;
        beatValue = 16;
      }
    }

    if (numBeats === 0) numBeats = 4;

    const timeSig = `${numBeats}/${beatValue}`;
    const voice = score.voice(staveNotes, { time: timeSig });

    // CRITICAL FIX: Apply accidentals logic based on Key Signature
    // This hides accidentals that are already in the key signature (e.g. F# in D Major)
    // and adds Naturals if needed (e.g. F Natural in D Major).
    Accidental.applyAccidentals([voice], keySpec);

    // Manual Beaming
    const beams: Beam[] = [];
    let currentBeamGroup: any[] = [];
    let lastBeamIndex: number | undefined = undefined;

    staveNotes.forEach((note, index) => {
        const item = items[index];
        if (item.beamGroupIndex !== undefined) {
             if (lastBeamIndex !== undefined && item.beamGroupIndex !== lastBeamIndex) {
                 if (currentBeamGroup.length > 0) {
                     beams.push(new Beam(currentBeamGroup));
                 }
                 currentBeamGroup = [];
             }
             currentBeamGroup.push(note);
             lastBeamIndex = item.beamGroupIndex;
        } else {
             if (currentBeamGroup.length > 0) {
                 beams.push(new Beam(currentBeamGroup));
                 currentBeamGroup = [];
             }
             lastBeamIndex = undefined;
        }
    });
    if (currentBeamGroup.length > 0) {
        beams.push(new Beam(currentBeamGroup));
    }

    const stave = system.addStave({
      voices: [voice]
    });

    stave.addClef(clef);
    stave.addKeySignature(keySpec);
    stave.addTimeSignature(timeSig);

    vf.draw();

    beams.forEach(b => b.setContext(vf.getContext()).draw());

  }, [items, clef, activeIndex, keyRoot, keyType]);

  return (
    <div className="w-full flex justify-center bg-white dark:bg-slate-800 rounded-xl shadow-inner p-4 overflow-x-auto mb-6 custom-scrollbar transition-colors duration-300">
       <div ref={containerRef} className="flex-shrink-0" /> 
    </div>
  );
};

